document.addEventListener("DOMContentLoaded",()=>{const e=document.querySelectorAll(".contact-link"),t=document.getElementById("copy-toast");let o;e.forEach(e=>{e.addEventListener("click",c=>{if(window.matchMedia("(pointer: fine)").matches){c.preventDefault();const n=e.getAttribute("data-copy");navigator.clipboard.writeText(n).then(()=>{t.classList.remove("hidden"),clearTimeout(o),o=setTimeout(()=>{t.classList.add("hidden")},2500)}).catch(e=>{console.error("Failed to copy text: ",e)})}})})});